import type { Metadata } from "next";
import "./globals.css";

export const metadata: Metadata = {
    title: "Asociación Aconiño | Apoyando la inclusión",
    description: "Asociación Aconiño, 30 Años apoyando la inclusión, enfocados en rehabilitación neurológica infantil.",
};

export default function RootLayout({
    children,
}: Readonly<{
    children: React.ReactNode;
}>) {
    return (
        <html lang="es">
            <body className="antialiased">
                <header className="bg-white shadow dark:bg-gray-800">
                    <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8 flex items-center justify-between">
                        <h1 className="text-3xl font-bold tracking-tight text-primary">Asociación Aconiño</h1>
                        <nav>
                            {/* Espacio para la navegación futura basada en WP */}
                        </nav>
                    </div>
                </header>
                <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
                    {children}
                </main>
                <footer className="bg-gray-100 dark:bg-gray-900 mt-auto py-8">
                    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center text-sm text-gray-500">
                        © {new Date().getFullYear()} Asociación Aconiño. Todos los derechos reservados.
                    </div>
                </footer>
            </body>
        </html>
    );
}
